const { id, name, content, chunks } = $input.first().json.body;

// Stage 1: Entity extraction
const entities = [];
const entityPatterns = [
  { regex: /ASCE\s*7|IBC|NFPA|ACI|AISC/gi, type: 'code' },
  { regex: /W\d+x\d+|HSS\d+/gi, type: 'steel_section' },
  { regex: /\d+\s*(?:psi|ksi|MPa|GPa)/gi, type: 'strength' },
  { regex: /(?:beam|column|foundation|slab|wall|footing)/gi, type: 'structural_element' },
];

for (const pattern of entityPatterns) {
  const matches = content.match(pattern.regex) || [];
  for (const match of [...new Set(matches)]) {
    entities.push({ name: match, type: pattern.type });
  }
}

return [{
  json: {
    id, name, content,
    chunks: chunks || 0,
    entities,
    entityCount: entities.length
  }
}];

const { entities, id } = $json;
const statements = entities.map(e => ({
  statement: `MATCH (d:Document {id: $docId}) MERGE (e:Entity {name: $name, type: $type}) MERGE (d)-[:MENTIONS]->(e)`,
  parameters: { docId: id, name: e.name, type: e.type }
}));

return [{ json: { statements, entityCount: entities.length, docId: id } }];
